import { createContext, useContext, useState, useEffect } from 'react';
import { supabase, api } from '../services/api';
import { useAuth } from './AuthContext';
import { useTableContext } from './TableContext';
import { useToast } from './ToastContext';
import SplitRequestModal from '../components/SplitRequestModal';

const NotificationContext = createContext({});

export const NotificationProvider = ({ children }) => {
    const { user } = useAuth();
    const { tableId } = useTableContext();
    const { addToast } = useToast();
    const [incomingRequest, setIncomingRequest] = useState(null);

    // 1. User Channel (Global - independent of Table)
    useEffect(() => {
        if (!user) return;

        console.log("­ƒöî [NotificationContext] Connecting User Channel:", user.id);

        const userChannel = supabase.channel(`user_notifications:${user.id}`)
            .on('broadcast', { event: 'request_split' }, (payload) => {
                console.log("­ƒöÑ NotificationContext received SPLIT request:", payload);
                const { orderId, itemName, targetIds, requesterName, requesterId } = payload.payload;

                setIncomingRequest({
                    id: Date.now(),
                    type: 'split_bill',
                    orderId,
                    itemName,
                    requesterName,
                    requesterId,
                    targetIds
                });
            })
            .on('broadcast', { event: 'split_response' }, async (payload) => {
                const { status, responderName, splitMetadata } = payload.payload;

                // I am the REQUESTER (User A). The Responder (User B) just said YES/NO.
                if (status === 'accepted') {
                    addToast(`${responderName} aceitou dividir! Processando...`, 'info');

                    if (splitMetadata) {
                        const { orderId, targetIds } = splitMetadata;
                        const fullOrder = await api.getOrder(orderId);
                        if (fullOrder && fullOrder.ordered_by === user.id) {
                            const success = await api.splitOrder(fullOrder, targetIds);
                            if (success) {
                                addToast("Divis├úo conclu├¡da com sucesso!", "success");
                            } else {
                                addToast("Erro ao processar divis├úo.", "error");
                            }
                        }
                    }
                } else {
                    addToast(`${responderName} recusou a divis├úo.`, 'warning');
                }
            })
            .on('broadcast', { event: 'request_order_share' }, (payload) => {
                const { itemDetails, targetUserId, requesterName, requesterId } = payload.payload;
                if (targetUserId === user.id) {
                    setIncomingRequest({
                        id: Date.now(),
                        type: 'join_order',
                        itemDetails,
                        itemName: itemDetails.name,
                        requesterName,
                        requesterId
                    });
                }
            })
            .subscribe();

        // Orders Status Channel (User specific)
        const orderChannel = supabase.channel(`orders_status:${user.id}`)
            .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders', filter: `ordered_by=eq.${user.id}` }, (payload) => {
                const newStatus = payload.new.status;
                const oldStatus = payload.old.status;
                const itemName = payload.new.name;
                if (newStatus !== oldStatus) {
                    if (newStatus === 'preparing') addToast(`­ƒæ¿ÔÇì­ƒì│ Preparando: ${itemName}`, 'info');
                    else if (newStatus === 'ready') addToast(`Ô£à Pronto: ${itemName}`, 'success');
                    else if (newStatus === 'delivered') addToast(`­ƒÜÇ Entregue: ${itemName}`, 'success');
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(userChannel);
            supabase.removeChannel(orderChannel);
        };
    }, [user]);

    // 2. Table Channel (Requires Table ID)
    useEffect(() => {
        if (!tableId) return;

        const tableChannel = supabase.channel(`table_notifications:${tableId}`)
            .on('broadcast', { event: 'request_split' }, (payload) => {
                // Legacy Table Broadcast listener (Backup)
                const { targetIds, orderId, itemName, requesterName, requesterId } = payload.payload;
                if (targetIds && targetIds.includes(user?.id)) {
                    setIncomingRequest(prev => {
                        if (prev && prev.orderId === orderId) return prev; // Dedup
                        return {
                            id: Date.now(),
                            type: 'split_bill',
                            orderId,
                            itemName,
                            requesterName,
                            requesterId,
                            targetIds
                        };
                    });
                }
            })
            .subscribe();

        return () => {
            supabase.removeChannel(tableChannel);
        };
    }, [tableId, user]);

    const handleAccept = async () => {
        console.log("­ƒƒó handleAccept CLICKED", { incomingRequest, tableId });
        if (!incomingRequest) return;

        // Capture data before closing modal
        const req = { ...incomingRequest };

        // Optimistic UI: Close modal immediately
        setIncomingRequest(null);

        try {
            if (req.type === 'split_bill') {
                // NEW FLOW: Send 'accepted' response to Requester. 
                // Requester (Owner) performs the split.

                const allParticipants = [req.requesterId, ...req.targetIds];
                const uniqueParticipants = [...new Set(allParticipants)];

                await api.sendSplitResponse(
                    req.requesterId,
                    'accepted',
                    user.name || 'Algu├®m',
                    {
                        orderId: req.orderId,
                        targetIds: uniqueParticipants
                    }
                );
                addToast("Voc├¬ aceitou! A divis├úo ser├í processada.", "info");
            } else if (req.type === 'join_order') {
                console.log("­ƒÜÇ Processing Join Order. Requester:", req.requesterId, "[v3-SECURE-LOOP]");

                // Helper to process a single item share
                const processSingleItem = async (pid, qty) => {
                    console.log(`­ƒöÆ Validating Item ID: ${pid} (Qty: ${qty})`);

                    // 1. Fetch Authoritative Price (Security)
                    // If it's a "virtual" half-item (half-...), we cannot fetch from DB. 
                    // We must trust the payload for these composite items.
                    const isVirtualItem = String(pid).startsWith('half-');
                    let realPrice = 0;
                    let dbProduct = null;

                    if (isVirtualItem) {
                        console.log(`Ôä╣´©Å Virtual Item detected (${pid}). Skipping DB Price Check.`);
                        // Try to get price from the item payload itself
                        // We search for the specific item in the list or use the top-level
                        const payloadItem = (req.itemDetails.items || []).find(i => i.productId === pid) || req.itemDetails;
                        realPrice = Number(payloadItem.price || payloadItem.originalPrice || 0);

                        // Create a mock dbProduct to satisfy downstream logic
                        dbProduct = {
                            id: pid,
                            name: payloadItem.name || 'Item Dividido',
                            price: realPrice
                        };
                    } else {
                        // Standard Security Check for Real Products
                        dbProduct = await api.getProduct(pid);

                        if (!dbProduct) {
                            console.error(`ÔØî Product ${pid} not found in DB. Skipping.`);
                            addToast(`Erro: Item n├úo encontrado (ID: ${pid})`, "error");
                            return false;
                        }
                        realPrice = Number(dbProduct.price);
                    }

                    if (!realPrice || realPrice <= 0) {
                        console.error(`ÔØî Invalid Price for ${dbProduct?.name}:`, realPrice);
                        return false;
                    }

                    // 2. Calculate Split (Dynamically based on payload)
                    const totalParts = req.itemDetails.totalParts || 2; // Default to 2 if not sent
                    const splitPrice = realPrice / totalParts;
                    const splitName = totalParts > 1 ? `1/${totalParts} ${dbProduct.name}` : dbProduct.name;
                    const debugName = `${splitName} [R$${splitPrice.toFixed(2)}]`; // DEBUG

                    console.log(`­ƒº« Math: ${realPrice} / ${totalParts} = ${splitPrice}`);

                    // 3. Create Order with FULL METADATA
                    const newOrder = await api.addOrder(req.itemDetails.tableId, {
                        productId: dbProduct.id, // Back to Real ID (Metadata explains price diff)
                        name: splitName,
                        price: splitPrice,
                        quantity: qty,
                        orderedBy: user.id,

                        // Metadata
                        isSplit: true,
                        splitParts: totalParts,
                        originalPrice: realPrice,
                        splitRequester: req.requesterId,
                        splitParticipants: [req.requesterId, req.targetUserId] // Basic 2-way split context
                    });

                    return !!newOrder;
                };

                const itemsToProcess = req.itemDetails.items || [{ productId: req.itemDetails.productId, quantity: req.itemDetails.quantity || 1 }];
                console.log("­ƒôª Items to process:", itemsToProcess);

                if (itemsToProcess.length === 0) {
                    addToast("Nenhum item para dividir.", "error");
                    return;
                }

                let successCount = 0;
                for (const item of itemsToProcess) {
                    // Filter out 'cart-total' nonsense if it crept in, but Menu.jsx should send real IDs now.
                    if (item.productId === 'cart-total') continue;

                    const success = await processSingleItem(item.productId, item.quantity);
                    if (success) successCount++;
                }

                if (successCount > 0) {
                    addToast(`Voc├¬ aceitou dividir ${successCount} iten(s)!`, 'success');
                    // Send Response
                    await api.sendSplitResponse(
                        req.requesterId,
                        'accepted',
                        user.name || 'Algu├®m'
                    );
                } else {
                    addToast("Falha ao processar divis├úo (Erros de valida├º├úo).", "error");
                }
            }
        } catch (e) {
            console.error("Critical Error processing split:", e);
            addToast("Erro cr├¡tico ao processar solicita├º├úo.", "error");
        }
    };

    const handleDecline = async () => {
        if (!incomingRequest) return;
        const req = { ...incomingRequest };
        setIncomingRequest(null);

        try {
            if (req.type === 'join_order') {
                console.log("­ƒÜ½ Sending Reject Response to User:", req.requesterId);
                await api.sendSplitResponse(
                    req.requesterId, // Target the ORIGINAL Requester
                    'rejected',
                    user.name || 'Algu├®m'
                );
            }
            addToast("Voc├¬ recusou a divis├úo.", "info");
        } catch (e) {
            console.error("Error declining request", e);
        }
    };

    return (
        <NotificationContext.Provider value={{}}>
            {children}
            {incomingRequest && (
                <SplitRequestModal
                    request={incomingRequest}
                    onAccept={handleAccept}
                    onDecline={handleDecline}
                />
            )}
        </NotificationContext.Provider>
    );
};

export const useNotification = () => useContext(NotificationContext);

import { createContext, useContext, useState, useEffect, useMemo } from 'react';
import { supabase, api } from '../services/api';
import { useAuth } from './AuthContext';

const TableContext = createContext({});

export const TableProvider = ({ children }) => {
    const { user } = useAuth();
    const [tableId, setTableId] = useState(localStorage.getItem('my_table_id'));
    const [dbUsers, setDbUsers] = useState([]);
    const [realtimeUsers, setRealtimeUsers] = useState([]);
    const [establishment, setEstablishment] = useState(null);

    // Sync tableId with localStorage
    const updateTableId = (id) => {
        if (id) {
            localStorage.setItem('my_table_id', id);
        } else {
            localStorage.removeItem('my_table_id');
        }
        setTableId(id);
    };

    // Load Establishment Data when Table ID changes
    useEffect(() => {
        const loadEstablishment = async () => {
            if (!tableId) {
                setEstablishment(null);
                // Reset Theme to Dark Mode Default (Black/Neutral) if no table
                document.documentElement.style.setProperty('--bg-primary', '#000000');
                document.documentElement.style.setProperty('--brand-color', '#dedede'); // Default Neutral
                return;
            }

            try {
                const tableData = await api.getTable(tableId);
                if (tableData && tableData.establishment) {
                    setEstablishment(tableData.establishment);

                } else {
                    setEstablishment(null);
                }
            } catch (err) {
                console.error("Error loading table context:", err);
                setEstablishment(null);
            }
        };

        loadEstablishment();
    }, [tableId]);

    // Apply Theme when Establishment Data is loaded/changes
    useEffect(() => {
        if (!establishment) {
            // Reset to default if no establishment
            document.documentElement.style.setProperty('--bg-primary', '#000000');
            document.documentElement.style.setProperty('--brand-color', '#dedede');
            document.documentElement.style.setProperty('--brand-contrast', '#000000');
            document.documentElement.style.setProperty('--brand-secondary', '#888888');
            document.documentElement.style.setProperty('--bg-gradient', 'none');
            return;
        }

        // APPLY THEME
        const brandColor = establishment.theme_color || '#dedede';
        const secondaryColor = establishment.theme_secondary_color || '#888888';

        document.documentElement.style.setProperty('--brand-color', brandColor);

        // Background & Gradient Logic
        const bgColor = establishment.theme_background_color || '#09090b';
        document.documentElement.style.setProperty('--bg-primary', bgColor);

        // Generate a subtle gradient (slightly lighter at top-center)
        const lighterBg = adjustBrightness(bgColor, 15); // Lighten by 15%
        const gradient = `radial-gradient(circle at 50% 0%, ${lighterBg}, ${bgColor})`;
        document.documentElement.style.setProperty('--bg-gradient', gradient);

        const contrastColor = getContrastYIQ(brandColor);
        document.documentElement.style.setProperty('--brand-contrast', contrastColor);

        // Secondary brand color
        const brandSecondary = establishment.theme_secondary_color || '#888888';
        document.documentElement.style.setProperty('--brand-secondary', brandSecondary);

    }, [establishment]);

    function adjustBrightness(col, percent) {
        const num = parseInt(col.replace('#', ''), 16);
        const amt = Math.round(2.55 * percent);
        const R = (num >> 16) + amt;
        const B = ((num >> 8) & 0x00FF) + amt;
        const G = (num & 0x0000FF) + amt;
        return '#' + (0x1000000 + (R < 255 ? R < 1 ? 0 : R : 255) * 0x10000 + (B < 255 ? B < 1 ? 0 : B : 255) * 0x100 + (G < 255 ? G < 1 ? 0 : G : 255)).toString(16).slice(1);
    }

    // Helper: Calculate Contrast
    function getContrastYIQ(hexcolor) {
        hexcolor = hexcolor.replace("#", "");
        if (hexcolor.length === 3) hexcolor = hexcolor.split('').map(c => c + c).join('');
        var r = parseInt(hexcolor.substr(0, 2), 16);
        var g = parseInt(hexcolor.substr(2, 2), 16);
        var b = parseInt(hexcolor.substr(4, 2), 16);
        var yiq = ((r * 299) + (g * 587) + (b * 114)) / 1000;
        return (yiq >= 128) ? '#000000' : '#ffffff';
    }


    // --- 1. DB Presence (Users with Active Orders) ---
    useEffect(() => {
        if (!tableId) {
            setDbUsers([]);
            return;
        }

        const fetchActiveUsers = async () => {
            const { data: orders } = await supabase
                .from('orders')
                .select('ordered_by')
                .eq('table_id', tableId)
                .neq('status', 'paid')
                .neq('name', '­ƒöö CHAMAR GAR├çOM');

            if (!orders) return;

            const rawIds = [...new Set(orders.map(o => o.ordered_by))];
            const foundUsers = [];

            // Separate UUIDs (registered users) from Strings (guest names)
            const uuidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
            const uuids = rawIds.filter(id => uuidPattern.test(id));
            const names = rawIds.filter(id => !uuidPattern.test(id));

            // A. Fetch Profiles for UUIDs
            if (uuids.length > 0) {
                const { data: profiles } = await supabase.from('users').select('*').in('id', uuids);
                if (profiles) {
                    profiles.forEach(p => foundUsers.push({
                        id: p.id,
                        name: p.name,
                        email: p.email,
                        phone: p.phone,
                        cpf: p.cpf,
                        passport: p.passport,
                        country: p.country || 'BR',
                        settings: p.settings || {},
                        avatar_url: p.avatar || `https://ui-avatars.com/api/?name=${p.name}&background=random`
                    }));
                }
            }

            // B. Create Stub Objects for Guest Names
            // B. Create Stub Objects for Guest Names
            names.forEach(n => {
                const isMe = n === user?.id; // Check if this guest ID matches current user
                foundUsers.push({
                    id: n,
                    name: n,
                    avatar_url: (isMe && user?.avatar) ? user.avatar : `https://ui-avatars.com/api/?name=${n}&background=random`
                });
            });

            setDbUsers(foundUsers);
        };

        fetchActiveUsers();

        // Listen for persistent order changes
        const orderChannel = supabase.channel(`ctx_orders:${tableId}`)
            .on('postgres_changes', { event: '*', schema: 'public', table: 'orders', filter: `table_id=eq.${tableId}` }, fetchActiveUsers)
            .subscribe();

        return () => {
            supabase.removeChannel(orderChannel);
        };
    }, [tableId]);

    // --- 2. Realtime Presence (Live Cursors) ---
    useEffect(() => {
        if (!user || !tableId) {
            setRealtimeUsers([]);
            return;
        }

        const channel = supabase.channel(`ctx_presence:${tableId}`, {
            config: {
                presence: {
                    key: user.id || 'guest',
                },
            },
        });

        channel
            .on('presence', { event: 'sync' }, () => {
                const newState = channel.presenceState();
                const liveList = [];
                for (let key in newState) {
                    if (newState[key].length > 0) {
                        liveList.push(newState[key][0]);
                    }
                }
                setRealtimeUsers(liveList);
            })
            .subscribe(async (status) => {
                if (status === 'SUBSCRIBED') {
                    const userData = {
                        id: user.id || 'guest',
                        name: user.name || 'Visitante',
                        email: user.email,
                        avatar_url: user.avatar || `https://ui-avatars.com/api/?name=${user.name || 'Visitante'}&background=random`
                    };
                    await channel.track(userData);
                }
            });

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user, tableId]);

    // Derived state: Merge DB and Realtime
    const onlineUsers = useMemo(() => {
        const map = new Map();
        // 1. Add DB Users first
        dbUsers.forEach(u => map.set(u.id, u));
        // 2. Add/Overwrite with Realtime Users
        realtimeUsers.forEach(u => map.set(u.id, u));

        const allUsers = Array.from(map.values());

        // Sort: Current User First, then Alphabetical
        return allUsers.sort((a, b) => {
            if (a.id === user?.id) return -1;
            if (b.id === user?.id) return 1;
            return (a.name || '').localeCompare(b.name || '');
        });
    }, [dbUsers, realtimeUsers, user?.id]);

    return (
        <TableContext.Provider value={{
            tableId,
            setTableId: updateTableId,
            onlineUsers,
            establishment
        }}>
            {children}
        </TableContext.Provider>
    );
};

export const useTableContext = () => useContext(TableContext);

import { useState, useEffect } from 'react';
import { useAuth } from '../../../context/AuthContext';
import { useNavigate } from 'react-router-dom';

export const useAvatarLogic = () => {
    const navigate = useNavigate();
    const { user, updateUser } = useAuth();

    // State
    const [config, setConfig] = useState({
        top: 'shortFlat',
        backgroundColor: 'transparent',
        accessories: 'none',
        hairColor: '4a312c',
        facialHair: 'none',
        facialHairColor: '4a312c',
        clothing: 'hoodie',
        clothesColor: '262e33',
        skinColor: 'edb98a',
        eyes: 'default', // Fixed
        mouth: 'default', // Fixed
        eyebrows: 'default' // Fixed
    });

    const [loading, setLoading] = useState(false);
    const [svgContent, setSvgContent] = useState(null);

    // Initialize from User Avatar URL
    useEffect(() => {
        if (user?.avatar) {
            try {
                const url = new URL(user.avatar);
                const params = new URLSearchParams(url.search);
                const newConfig = { ...config };

                ['top', 'accessories', 'hairColor', 'facialHair', 'clothing', 'clothesColor', 'skinColor', 'backgroundColor'].forEach(key => {
                    const val = params.get(key);
                    if (val) newConfig[key] = val;
                });

                if (params.get('topProbability') === '0') {
                    newConfig.top = 'noHair';
                }

                setConfig(newConfig);
            } catch (e) {
                console.error("Error parsing avatar URL", e);
            }
        }
    }, [user]);

    // Fetch SVG
    useEffect(() => {
        const fetchAvatar = async () => {
            const url = getAvatarUrl();
            try {
                const response = await fetch(url);
                if (!response.ok) throw new Error(`DiceBear API Error: ${response.status}`);
                const text = await response.text();
                setSvgContent(text);
            } catch (err) {
                console.error("Failed to load avatar:", err);
                setSvgContent(null);
            }
        };

        const timeoutId = setTimeout(fetchAvatar, 300);
        return () => clearTimeout(timeoutId);
    }, [config, user]);


    const getAvatarUrl = () => {
        const baseUrl = 'https://api.dicebear.com/9.x/avataaars/svg';
        const params = new URLSearchParams();

        params.append('seed', user?.email || 'user');

        if (config.backgroundColor && config.backgroundColor !== 'transparent') {
            params.append('backgroundColor', config.backgroundColor);
        }

        if (config.top === 'noHair') {
            params.append('topProbability', '0');
        } else {
            params.append('top', config.top);
            params.append('topProbability', '100');
        }

        if (config.accessories === 'none') {
            params.append('accessoriesProbability', '0');
        } else {
            params.append('accessories', config.accessories);
            params.append('accessoriesProbability', '100');
        }

        if (config.facialHair === 'none') {
            params.append('facialHairProbability', '0');
        } else {
            params.append('facialHair', config.facialHair);
        }

        if (config.clothing) params.append('clothing', config.clothing);
        if (config.clothesColor) params.append('clothesColor', config.clothesColor);
        if (config.skinColor) params.append('skinColor', config.skinColor);
        if (config.hairColor) params.append('hairColor', config.hairColor);

        params.append('eyes', 'default');
        params.append('mouth', 'default');
        params.append('eyebrows', 'default');

        return `${baseUrl}?${params.toString()}`;
    };

    // Need to trigger a table presence update if possible.
    // Ideally, we just rely on Realtime, but for persistence we want the DB to reflect it for the next reload.
    const handleSave = async () => {
        setLoading(true);
        const newAvatar = getAvatarUrl();
        await updateUser({ avatar: newAvatar });
        // After updating user, if we are in a table, we should ideally poke the table context 
        // but AuthContext update triggers TableContext realtime update automatically.
        navigate(-1);
        setLoading(false);
    };

    // Helper for cycling options
    const cycleOption = (key, array, direction) => {
        const currentIndex = array.indexOf(config[key]);
        let newIndex = direction === 'next' ? currentIndex + 1 : currentIndex - 1;
        if (newIndex >= array.length) newIndex = 0;
        if (newIndex < 0) newIndex = array.length - 1;
        setConfig(prev => ({ ...prev, [key]: array[newIndex] }));
    };

    return {
        config, setConfig,
        loading, svgContent,
        handleSave, cycleOption, navigate
    };
};

import { ArrowLeft, ChevronLeft, ChevronRight, Save } from 'lucide-react';
import { useAvatarLogic } from './hooks/useAvatarLogic';
import * as options from './utils/avatarOptions';

const AvatarEditor = () => {
    const {
        config, setConfig,
        loading, svgContent,
        handleSave, cycleOption, navigate
    } = useAvatarLogic();

    return (
        <div className="container fade-in" style={{ height: '100vh', display: 'flex', flexDirection: 'column', padding: 0, overflow: 'hidden' }}>
            {/* Header */}
            <header style={{ padding: '1rem', display: 'flex', alignItems: 'center', gap: '1rem', flex: '0 0 auto', background: 'transparent', zIndex: 10 }}>
                <button onClick={() => navigate(-1)} className="btn-ghost" style={{ width: 'auto', padding: 0 }}>
                    <ArrowLeft color="white" />
                </button>
                <h2 style={{ margin: 0 }}>Editar Avatar</h2>
            </header>

            {/* Preview */}
            <section style={{ flex: '0 0 auto', display: 'flex', justifyContent: 'center', paddingBottom: '1rem', background: 'transparent', zIndex: 5, borderBottom: '1px solid var(--border-color)' }}>
                <div style={{
                    width: '180px', height: '180px',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    borderRadius: '50%', overflow: 'hidden',
                    border: '4px solid var(--border-color)',
                }}>
                    {svgContent ? (
                        <div
                            style={{ width: '100%', height: '100%' }}
                            dangerouslySetInnerHTML={{ __html: svgContent }}
                        />
                    ) : (
                        <div className="spinner" />
                    )}
                </div>
            </section>

            {/* Controls */}
            <div style={{ flex: 1, overflowY: 'auto', padding: '2rem 1rem 120px 1rem', width: '100%', maxWidth: '500px', margin: '0 auto' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>

                    <ColorSection
