                    style={{ width: '100%', maxWidth: '400px', boxShadow: '0 4px 15px rgba(99,102,241,0.4)' }}
                >
                    {loading ? 'Salvando...' : (
                        <>
                            <Save size={20} /> Salvar Visual
                        </>
                    )}
                </button>
            </div>
        </div>
    );
};

