                            <span>{subtotal.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}</span>
                        </div>
                        <button onClick={() => setShowItemsInfo(false)} className="btn btn-primary" style={{ marginTop: '0.5rem', flexShrink: 0 }}>Fechar</button>
                    </div>
                </div>
            )}
        </div>
    );
};

// Styles
const modalOverlayStyle = { position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.9)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 100, padding: '1rem' };
const bottomSheetOverlayStyle = { position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.6)', display: 'flex', alignItems: 'end', justifyContent: 'center', zIndex: 110, padding: 0 };
const bottomSheetStyle = { width: '100%', maxWidth: '480px', backgroundColor: 'var(--bg-secondary)', borderTopLeftRadius: '24px', borderTopRightRadius: '24px', padding: '2rem', animation: 'slideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1)', position: 'relative' };
const handleStyle = { width: '40px', height: '4px', backgroundColor: 'var(--bg-tertiary)', borderRadius: '2px', margin: '0 auto 1.5rem auto', flexShrink: 0 };
const rowStyle = { display: 'flex', justifyContent: 'space-between', padding: '0.75rem 0', borderBottom: '1px solid var(--bg-tertiary)' };

export default Payment;

import { Save as SaveIcon, X } from 'lucide-react';
import PhoneInput, { formatPhoneNumber } from 'react-phone-number-input';
import { maskCPF } from '../../../utils/masks'; // Ensure this path is correct relative to this file: pages/Profile/components/FieldEditor
// Wait, path is ../../../utils/masks 
// pages/Profile/components -> ../../../ -> src/utils OK.

const FieldEditor = ({
    label, field, icon: Icon, value, isSelect, options, isPhone,
    editing, startEdit, cancelEdit, saveField, setTempValue, tempValue, saving,
    user, localCountry, setLocalCountry
}) => {
    const isEditingThis = editing === field;

    // DISPLAY LOGIC
    let displayValue = value;
    if (field === 'phone' && value) displayValue = formatPhoneNumber(value);
    if (field === 'cpf') displayValue = maskCPF(value);
    if (field === 'country') {
        const opt = options?.find(o => o.value === value);
        displayValue = opt ? opt.label : value;
    }

    const handlePhoneChange = (val) => {
        setTempValue(val);
    };

    const handleCountryChange = (countryCode) => {
        if (countryCode) {
            setLocalCountry(countryCode);
        }
    };

    // Helper for non-phone inputs
    const extractValue = (field, val) => {
        if (field === 'cpf') return maskCPF(val);
        return val;
    }

    return (
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
            <Icon size={20} color="var(--primary)" />
            <div style={{ flex: 1 }}>
                <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>{label}</p>

                {isEditingThis ? (
                    isPhone ? (
                        <div className="phone-input-container">
                            <PhoneInput
                                international
                                defaultCountry={localCountry}
                                value={tempValue}
                                onChange={handlePhoneChange}
                                onCountryChange={handleCountryChange}
                                className="input-field"
                                style={{ background: 'transparent', border: 'none', padding: 0, marginBottom: '0' }}
                                autoFocus
                            />
                        </div>
                    ) : isSelect ? (
                        <select
                            value={tempValue}
                            onChange={e => setTempValue(e.target.value)}
                            className="input-field"
                            style={{ margin: 0, padding: '0.5rem', width: '100%', backgroundColor: 'var(--bg-secondary)', color: 'var(--text-primary)', border: '1px solid var(--bg-tertiary)' }}
                        >
                            {options.map(opt => (
                                <option key={opt.value} value={opt.value}>{opt.label}</option>
                            ))}
                        </select>
                    ) : (
                        <input
                            value={tempValue}
                            onChange={e => setTempValue(extractValue(field, e.target.value))}
                            className="input-field"
                            style={{ margin: 0, padding: '0.5rem', flex: 1 }}
                            autoFocus
                        />
                    )
                ) : (
                    <p>{displayValue || 'N├úo informado'}</p>
                )}
            </div>

            {field !== 'cpf' && (
                isEditingThis ? (
                    <div style={{ display: 'flex', gap: '0.5rem', height: '60px', alignItems: 'flex-end' }}>
                        <button onClick={saveField} disabled={saving} className="btn-ghost" style={{ color: 'var(--success)' }}>
                            <SaveIcon size={18} />
                        </button>
                        <button onClick={cancelEdit} disabled={saving} className="btn-ghost" style={{ color: 'var(--danger)' }}>
                            <X size={18} />
                        </button>
                    </div>
                ) : (
                    <button onClick={() => startEdit(field, value)} className="btn-ghost" style={{ width: 'auto', fontSize: '0.9rem', color: 'var(--primary)' }}>
                        Alterar
                    </button>
                )
            )}
        </div>
    );
};

export default FieldEditor;

import { useNavigate } from 'react-router-dom';
import { X, Martini, Keyboard } from 'lucide-react';
import { api } from '../services/api';
import { useState } from 'react';
import { useTableContext } from '../context/TableContext';
import { useToast } from '../context/ToastContext';

const Scanner = () => {
    const navigate = useNavigate();
    const { setTableId } = useTableContext();
    const [manualCode, setManualCode] = useState('');
    const [error, setError] = useState('');
    const [showInput, setShowInput] = useState(false);



    const handleSimulation = async () => {
        try {
            // Fetch real tables to get a valid ID
            const tables = await api.getTables();
            if (tables.length > 0) {
                const validTableId = tables[0].id;

                // Force theme cleanup before entering (optional safe guard)
                document.documentElement.style.setProperty('--brand-color', '#f59e0b');

                setTableId(validTableId); // Context handles localstorage
                navigate('/');
            } else {
                addToast('Nenhuma mesa encontrada no sistema para simular.', 'error');
            }
        } catch (error) {
            console.error("Simulation error", error);
            setTableId('123');
            navigate('/');
        }
    };

    const handleManualSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!manualCode || manualCode.length < 3) return;

        try {
            const table = await api.getTableByCode(manualCode);
            if (table && table.id) {
                setTableId(table.id);
                navigate('/');
            } else {
                setError('Mesa n├úo encontrada. Verifique o c├│digo.');
            }
        } catch (err) {
            console.error(err);
            setError('Erro ao buscar mesa.');
        }
    };

    return (
        <div style={{
            position: 'fixed', inset: 0,
            background: 'linear-gradient(180deg, #000000 0%, #1a1a1a 100%)',
            zIndex: 999
        }}>
            <button
                onClick={() => navigate(-1)}
                style={{ position: 'absolute', top: '2rem', right: '2rem', color: 'white', zIndex: 10, background: 'none', border: 'none', cursor: 'pointer' }}
            >
                <X size={32} />
            </button>

            <div style={{
                height: '100%', display: 'flex', flexDirection: 'column',
                alignItems: 'center', justifyContent: 'center'
            }}>
                {/* QR Scanner Mock */}
                {!showInput ? (
                    <>
                        <div
                            onClick={handleSimulation}
                            style={{
                                width: '280px', height: '280px',
                                border: '4px solid var(--primary)', borderRadius: '24px',
                                boxShadow: '0 0 0 9999px rgba(0,0,0,0.85)', // Darker overlay
                                cursor: 'pointer',
                                position: 'relative',
                                display: 'flex', alignItems: 'center', justifyContent: 'center'
                            }}
                        >
                            <div style={{
                                position: 'absolute', inset: 0,
                                background: 'linear-gradient(180deg, transparent, rgba(99, 102, 241, 0.4), transparent)',
                                animation: 'scan 2s linear infinite',
                                pointerEvents: 'none'
                            }} />

                            {/* Drink Icon in middle as requested */}
                            <Martini size={48} color="white" style={{ opacity: 0.5 }} />
                        </div>

                        <p style={{ marginTop: '2rem', color: 'white', fontSize: '1.25rem', fontWeight: 600 }}>
                            Aponte para o QR Code
                        </p>
                        <p style={{ marginTop: '0.5rem', color: 'rgba(255,255,255,0.5)', fontSize: '0.9rem', marginBottom: '3rem' }}>
                            (Toque no quadrado para simular)
                        </p>

                        <button
                            onClick={() => setShowInput(true)}
                            className="btn"
                            style={{
                                background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.2)',
                                color: 'white', padding: '1rem 2rem', borderRadius: '12px',
                                display: 'flex', alignItems: 'center', gap: '10px'
                            }}
                        >
                            <Keyboard size={20} />
                            Inserir c├│digo da mesa
                        </button>
                    </>
                ) : (
                    /* Manual Input View */
                    <div style={{ width: '100%', maxWidth: '320px', padding: '2rem', animation: 'fadeIn 0.3s' }}>
                        <h2 style={{ color: 'white', textAlign: 'center', marginBottom: '2rem' }}>C├│digo da Mesa</h2>

                        <form onSubmit={handleManualSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <input
                                type="text"
                                value={manualCode}
                                onChange={(e) => setManualCode(e.target.value.toUpperCase())}
                                placeholder="Ex: AA0001"
                                autoFocus
                                style={{
                                    padding: '16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.4)',
                                    background: '#000000', color: 'white',
                                    fontSize: '1.2rem', textTransform: 'uppercase', outline: 'none',
                                    textAlign: 'center', letterSpacing: '2px'
                                }}
                            />
                            <button
                                type="submit"
                                className="btn btn-primary"
                                style={{
                                    padding: '1rem', borderRadius: '12px', justifyContent: 'center',
                                    fontSize: '1rem', fontWeight: 'bold'
                                }}
                            >
                                Entrar na Mesa
                            </button>

                            <button
                                type="button"
                                onClick={() => setShowInput(false)}
                                style={{
                                    background: 'none', border: 'none', color: 'rgba(255,255,255,0.6)',
                                    padding: '1rem', cursor: 'pointer', textDecoration: 'underline'
                                }}
                            >
                                Voltar para Camera
                            </button>
                        </form>
                        {error && (
                            <div style={{ marginTop: '1rem', padding: '1rem', background: 'rgba(239, 68, 68, 0.2)', color: '#fca5a5', borderRadius: '8px', textAlign: 'center' }}>
                                {error}
                            </div>
                        )}
                    </div>
                )}
            </div>
            <style>{`
                @keyframes scan {
                    0% { transform: translateY(-100%); }
                    100% { transform: translateY(100%); }
                }
                @keyframes fadeIn {
                    from { opacity: 0; transform: translateY(10px); }
                    to { opacity: 1; transform: translateY(0); }
                }
            `}</style>
        </div>
    );
};

export default Scanner;

import React from 'react';
import { Users } from 'lucide-react';

const TabOrderList = ({ myOrders, othersOrders, showAll, setShowAll, resolveName, onSplitItem, onlineUsers = [] }) => {

    const formatPrice = (val) => val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

    // Helper to get user info
    const getUserInfo = (id) => {
        if (!id) return { name: '?', avatar: null };
        const found = onlineUsers.find(u => u.id === id);
        return found || { name: '?', avatar_url: null };
    };

    const AvatarStack = ({ requesterId, participants = [] }) => {
        const requester = getUserInfo(requesterId);
        // "Others" are participants excluding the requester
        const othersIds = participants.filter(id => id !== requesterId);

        return (
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                {/* Requester Avatar (Main) */}
                <div style={{ width: '24px', height: '24px', borderRadius: '50%', overflow: 'hidden', border: '1px solid var(--primary)' }}>
                    <img
                        src={requester.avatar_url || `https://ui-avatars.com/api/?name=${requester.name || 'User'}&background=random`}
                        alt={requester.name}
                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                </div>

                {othersIds.length > 0 && (
                    <>
                        <div style={{ width: '1px', height: '14px', background: 'var(--text-secondary)', opacity: 0.3 }}></div>

                        {/* Stacked Others */}
                        <div style={{ display: 'flex', paddingLeft: '4px' }}>
                            {othersIds.map((uid, idx) => {
                                const u = getUserInfo(uid);
                                return (
                                    <div key={uid} style={{
                                        width: '20px', height: '20px', borderRadius: '50%', overflow: 'hidden',
                                        border: '1px solid white', marginLeft: idx === 0 ? 0 : '-8px',
                                        zIndex: 10 - idx
                                    }}>
                                        <img
                                            src={u.avatar_url || `https://ui-avatars.com/api/?name=${u.name || 'User'}&background=random`}
                                            alt={u.name}
                                            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                        />
                                    </div>
                                );
                            })}
                        </div>
                    </>
                )}
            </div>
        );
    };

    // Helper for Status
    const getStatusConfig = (s) => {
        switch (s) {
            case 'pending': return { label: 'Aguardando', color: '#b45309', bg: '#fef3c7' };
            case 'preparing': return { label: 'Preparando', color: '#1d4ed8', bg: '#dbeafe' };
            case 'ready':
            case 'delivered':
            case 'completed': return { label: 'Entregando', color: '#15803d', bg: '#dcfce7' };
            case 'paid': return { label: 'Pago', color: '#15803d', bg: '#dcfce7' };
            default: return { label: s, color: '#374151', bg: '#f3f4f6' };
        }
    };

    // Helper to calculate Display Price honoring Metadata
    const getDisplayPrice = (item) => {
        if (item.is_split && item.split_parts > 1 && item.original_price > 0) {
            return Number(item.original_price) / item.split_parts;
        }
        return Number(item.price);
    };

    // Calculate Others Total
    const othersSubtotal = othersOrders.reduce((acc, item) => acc + (getDisplayPrice(item) * item.quantity), 0);

    return (
        <div style={{ display: 'grid', gap: '1rem', marginBottom: '6rem' }}>
            {/* Meus Pedidos */}
            <h4 style={{ margin: '0 0 0.5rem 0', opacity: 0.9 }}>Seus Pedidos (Toque para dividir)</h4>
            {myOrders.length === 0 ? (
                <div style={{ textAlign: 'center', color: 'var(--text-secondary)', padding: '1rem', background: 'var(--bg-tertiary)', borderRadius: '12px' }}>
                    Voc├¬ ainda n├úo pediu nada.
                </div>
            ) : (
                myOrders.map(item => {
                    const statusConfig = getStatusConfig(item.status);

                    // Logic for Split Tag
                    const isSplit = item.is_split && item.split_parts > 1;
                    const cleanName = isSplit
                        ? item.name.replace(/^\d+\s*\/\s*\d+\s+(.*)/, '$1').replace(/^\d+\s*\/\s*\d+\s+/, '')
                        : item.name;

                    const participants = item.split_participants || (isSplit ? [] : []);

                    return (
                        <div
                            key={item.id}
                            onClick={() => onSplitItem(item)}
                            className="card"
                            style={{
                                marginBottom: 0, borderLeft: '4px solid var(--primary)', cursor: 'pointer',
                                position: 'relative'
                            }}
                        >
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                <span style={{ fontWeight: '600', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: isSplit ? '6px' : '12px' }}>
                                    {item.quantity}x
                                    {isSplit && (
                                        <span style={{
                                            fontSize: '0.7rem',
                                            background: '#374151',
                                            color: '#f9fafb',
                                            padding: '1px 6px',
                                            borderRadius: '4px',
                                            fontWeight: '400',
                                            verticalAlign: 'middle',
                                            display: 'inline-flex',
                                            alignItems: 'center',
                                            height: '18px',
                                            marginRight: '2px'
                                        }}>
                                            1/{item.split_parts}
                                        </span>
                                    )}
                                    {cleanName}
                                </span>
                                <span style={{ fontWeight: '700' }}>{formatPrice(getDisplayPrice(item) * item.quantity)}</span>
                            </div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <AvatarStack requesterId={item.split_requester || item.ordered_by} participants={participants} />

                                <span style={{
                                    fontSize: '0.7rem', padding: '3px 8px', borderRadius: '6px',
                                    backgroundColor: statusConfig.bg,
                                    color: statusConfig.color,
                                    fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.5px',
                                    marginLeft: 'auto'
                                }}>
                                    {statusConfig.label}
                                </span>
                                {!isSplit && (
                                    <span style={{
                                        fontSize: '0.7rem', color: 'var(--text-secondary)',
                                        border: '1px solid var(--text-secondary)', padding: '2px 6px', borderRadius: '4px'
                                    }}>
                                        DIVIDIR
                                    </span>
                                )}
                            </div>
                        </div>
                    );
                })
            )}

            {/* Pedidos da Mesa (Toggle) */}
            {othersOrders.length > 0 && (
                <div style={{ marginTop: '1rem' }}>
                    <div style={{
                        display: 'flex', alignItems: 'center', gap: '1rem',
                        marginBottom: '1rem', opacity: 0.8
                    }}>
                        <div style={{ height: '1px', flex: 1, background: 'var(--bg-tertiary)' }}></div>
                        <button
                            onClick={() => setShowAll(!showAll)}
                            style={{
                                background: 'var(--bg-tertiary)', border: 'none', borderRadius: '20px',
                                padding: '0.5rem 1.2rem', color: 'var(--text-secondary)', fontSize: '0.85rem',
                                display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer'
                            }}
                        >
                            <Users size={16} />
                            {showAll ? 'Ocultar Mesa' : `Ver Mesa (+${othersOrders.length})`}
                        </button>
                        <div style={{ height: '1px', flex: 1, background: 'var(--bg-tertiary)' }}></div>
                    </div>

                    {showAll && (
                        <div style={{ display: 'grid', gap: '1rem', animation: 'fadeIn 0.3s' }}>
                            {othersOrders.map(item => {
                                const statusConfig = getStatusConfig(item.status);
                                const isSplit = item.is_split && item.split_parts > 1;
                                const cleanName = isSplit
                                    ? item.name.replace(/^\d+\s*\/\s*\d+\s+(.*)/, '$1').replace(/^\d+\s*\/\s*\d+\s+/, '')
                                    : item.name;
                                const participants = item.split_participants || [];

                                return (
                                    <div key={item.id} className="card" style={{ marginBottom: 0, opacity: 0.85, background: 'var(--bg-tertiary)' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                            <span style={{ fontWeight: '600', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '6px' }}>
                                                {item.quantity}x
                                                {isSplit && (
                                                    <span style={{
                                                        fontSize: '0.7rem',
                                                        background: '#374151',
                                                        color: '#f9fafb',
                                                        padding: '1px 6px',
                                                        borderRadius: '4px',
                                                        fontWeight: '400',
                                                        verticalAlign: 'middle',
                                                        display: 'inline-flex',
                                                        alignItems: 'center',
                                                        height: '18px',
                                                        marginRight: '2px'
                                                    }}>
                                                        1/{item.split_parts}
                                                    </span>
                                                )}
                                                {cleanName}
                                            </span>
                                            <span style={{ fontWeight: '700', color: 'var(--text-secondary)' }}>{formatPrice(getDisplayPrice(item) * item.quantity)}</span>
                                        </div>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                            <AvatarStack requesterId={item.split_requester || item.ordered_by} participants={participants} />

                                            <span style={{
                                                fontSize: '0.7rem', padding: '3px 8px', borderRadius: '6px',
                                                backgroundColor: 'var(--bg-secondary)', // Neutral for others
                                                color: statusConfig.color,
                                                fontWeight: '700', textTransform: 'uppercase', letterSpacing: '0.5px',
                                                border: '1px solid rgba(0,0,0,0.05)',
                                                marginLeft: 'auto'
                                            }}>
                                                {statusConfig.label}
                                            </span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}
            <style>{`
                @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
            `}</style>
        </div>
    );
};

export default TabOrderList;

import { useNavigate } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';
import { useState, useEffect } from 'react';
import { api, supabase } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { useTablePresence } from '../../hooks/useTablePresence';
import { useToast } from '../../context/ToastContext';
import SplitTabItemModal from '../../components/SplitTabItemModal';

// Components
import TabOrderList from './components/TabOrderList';
import TabFooter from './components/TabFooter';

// Hooks
import { useSplitLogic } from './hooks/useSplitLogic';

const TabDetail = () => {
    const navigate = useNavigate();
    const { user } = useAuth();
    const { addToast } = useToast();
    const { onlineUsers } = useTablePresence();
    const [loading, setLoading] = useState(true);
    const [orders, setOrders] = useState([]);
    const [establishment, setEstablishment] = useState(null);
    const [tableNumber, setTableNumber] = useState(null);
    const [showAll, setShowAll] = useState(false);

    // --- DATA LOADING ---
    const loadTab = async () => {
        const tableId = localStorage.getItem('my_table_id');
        if (!tableId) {
            navigate('/scanner');
            return;
        }
        try {
            const tableData = await api.getTable(tableId);
            if (tableData) {
                setOrders(tableData.orders || []);
                setTableNumber(tableData.number);
                if (tableData.establishment) {
                    setEstablishment(tableData.establishment);
                }
            }
        } catch (error) {
            console.error("Error loading tab", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadTab();
        const tableId = localStorage.getItem('my_table_id');
        if (tableId) {
            const channel = supabase.channel(`tab_detail:${tableId}`)
                .on('postgres_changes', { event: '*', schema: 'public', table: 'orders', filter: `table_id=eq.${tableId}` }, () => {
                    loadTab();
                })
                .subscribe();
            return () => { supabase.removeChannel(channel); };
        }
    }, [navigate]);

    // --- LOGIC HELPERS ---
    const resolveName = (id) => {
        if (!id) return 'Desconhecido';
        if (id === user?.id) return 'Voc├¬';
        const found = onlineUsers.find(u => u.id === id);
        if (found) return found.name;
        if (id === '22222222-2222-2222-2222-222222222222') return 'Amiga da Demo';
        if (id === '00000000-0000-0000-0000-000000000000') return 'Demo User';
        if (!/^[0-9a-f]{8}-[0-9a-f]{4}/.test(id)) return id;
        return 'Cliente';
    };

    const getDisplayPrice = (item) => {
        if (item.is_split && item.split_parts > 1 && item.original_price > 0) {
            return Number(item.original_price) / item.split_parts;
        }
        return Number(item.price);
    };

    const visibleOrders = orders.filter(o => {
        const realPrice = getDisplayPrice(o);
        const name = o.name || 'Unnamed';
        const isInternal = name === '­ƒöö CHAMAR GAR├çOM' || o.status === 'service_call';
        const isPaid = o.status === 'paid';
        const isPricePositive = realPrice > 0;
        return !isInternal && !isPaid && isPricePositive;
    });

    // --- SPLIT LOGIC HOOK ---
    const {
        splitItem, selectedUsersToSplit, isEditingSplit, existingParticipants,
        handleItemClick, handleModalConfirm, closeSplitModal
    } = useSplitLogic(visibleOrders);

    // Derived Lists
    const myOrdersList = visibleOrders.filter(o => o.ordered_by === user?.id);
    const othersOrdersList = visibleOrders.filter(o => o.ordered_by !== user?.id);
    const mySubtotal = myOrdersList.reduce((acc, item) => acc + (getDisplayPrice(item) * item.quantity), 0);

    if (loading) return <TabDetailSkeleton />;

    return (
        <div className="container" style={{ paddingBottom: '100px' }}>
            <header style={{ padding: '1rem 0', display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
                <button onClick={() => navigate(-1)} className="btn-ghost" style={{ width: 'auto', padding: 0 }}>
                    <ArrowLeft />
                </button>
                <div>
                    <h2 style={{ fontSize: '1.25rem' }}>{establishment?.name || 'Restaurante'}</h2>
                    <span style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Mesa {tableNumber || '?'}</span>
                </div>
            </header>

            <TabOrderList
                myOrders={myOrdersList}
                othersOrders={othersOrdersList}
                showAll={showAll}
                setShowAll={setShowAll}
                resolveName={resolveName}
                onSplitItem={handleItemClick}
                onlineUsers={onlineUsers}
            />

            {splitItem && (
                <SplitTabItemModal
                    item={splitItem}
                    currentUser={user}
                    onlineUsers={onlineUsers}
                    initialSelectedUsers={selectedUsersToSplit}
                    disabledUsers={existingParticipants}
                    onClose={closeSplitModal}
                    onConfirm={handleModalConfirm}
                    confirmLabel={isEditingSplit ? 'Atualizar Divis├úo' : 'Confirmar Divis├úo'}
                />
            )}

            <TabFooter
                mySubtotal={mySubtotal}
                onCallWaiter={() => addToast("Gar├ºom chamado!", "success")}
            />
        </div>
    );
};

const TabDetailSkeleton = () => (
    <div className="container" style={{ paddingBottom: '100px' }}>
        <style>{`
            @keyframes skeleton-pulse { 0% { opacity: 0.6; } 50% { opacity: 0.3; } 100% { opacity: 0.6; } }
            .skeleton { background: var(--bg-tertiary); border-radius: 4px; animation: skeleton-pulse 1.5s ease-in-out infinite; }
        `}</style>

        <div style={{ padding: '1rem 0', display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
            <div className="skeleton" style={{ width: '32px', height: '32px', borderRadius: '50%' }} />
            <div>
                <div className="skeleton" style={{ width: '150px', height: '20px', marginBottom: '4px' }} />
                <div className="skeleton" style={{ width: '80px', height: '14px' }} />
            </div>
        </div>

        <div style={{ marginBottom: '0.5rem', width: '200px', height: '16px' }} className="skeleton" />
        <div style={{ display: 'grid', gap: '1rem', marginBottom: '2rem' }}>
            {[1, 2].map(i => (
                <div key={i} className="card" style={{ marginBottom: 0, borderLeft: '4px solid var(--bg-tertiary)' }}>
                    <div className="skeleton" style={{ width: '60%', height: '20px', marginBottom: '0.5rem' }} />
                    <div className="skeleton" style={{ width: '40%', height: '16px' }} />
                </div>
            ))}
        </div>
    </div>
);

export default TabDetail;

import { supabase } from '../../supabase';

export const establishmentQueries = {
    getEstablishments: async () => {
        let { data, error } = await supabase
            .from('establishments')
            .select('*');
        return data || [];
    },
    getEstablishment: async (id) => {
        let { data, error } = await supabase
            .from('establishments')
            .select('*')
            .eq('id', id)
            .single();
        return data;
    },
};
